        // Direct Cosmos SQL (unchanged — c.Discriminator is preserved)
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // EF Core 9 breaking change #3: Sync APIs (ToList, First, etc.) removed
        // for Cosmos provider. Must use async equivalents.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

